const webhook = $('Deploy Webhook').first().json;
const businessId = webhook.body.businessId;
const businessName = webhook.body.businessName;
const repoName = webhook.body.repoName;
const techStack = webhook.body.techStack || 'nextjs';
const prdContent = webhook.body.prdContent || '';

// Claude Code GitHub Action YAML (same template as bayflow)
const claudeYml = `name: Claude Code

on:
  issue_comment:
    types: [created]
  pull_request_review_comment:
    types: [created]
  issues:
    types: [opened, assigned]
  pull_request_review:
    types: [submitted]

jobs:
  claude:
    if: |
      (github.event_name == 'issue_comment' && contains(github.event.comment.body, '@claude')) ||
      (github.event_name == 'pull_request_review_comment' && contains(github.event.comment.body, '@claude')) ||
      (github.event_name == 'issues' && (contains(github.event.issue.body, '@claude') || contains(github.event.issue.title, '@claude')))
    runs-on: ubuntu-latest
    timeout-minutes: 30
    permissions:
      contents: write
      pull-requests: write
      issues: write
      id-token: write
      actions: read
    steps:
      - name: Checkout repository
        uses: actions/checkout@v6
        with:
          fetch-depth: 1

      - name: Run Claude Code
        id: claude
        uses: anthropics/claude-code-action@v1
        with:
          anthropic_api_key: \${{ secrets.ANTHROPIC_API_KEY }}
          claude_args: |
            --model claude-opus-4-6
            --max-turns 25
`;

// Parse design system from PRD if available
let primaryColor = '#2563EB';
let secondaryColor = '#1E40AF';
let accentColor = '#F59E0B';
let headingFont = 'Space Grotesk';
let bodyFont = 'Inter';
let designAesthetic = 'Clean, modern, professional. Trustworthy.';
let dataModel = '';
let features = '';
let pagesRoutes = '';
let pricingTiers = '';
let integrations = '';
let seoKeywords = '';
let launchChecklist = '';
let competitiveWeaknesses = '';
let targetPersona = '';

if (prdContent) {
  // Extract design system section
  const designMatch = prdContent.match(/## 6\.\s*Design System[\s\S]*?(?=## 7\.|$)/);
  if (designMatch) {
    const ds = designMatch[0];
    const colorMatch = ds.match(/Primary color[^#]*(#[0-9a-fA-F]{6})/);
    if (colorMatch) primaryColor = colorMatch[1];
    const secMatch = ds.match(/Secondary color[^#]*(#[0-9a-fA-F]{6})/);
    if (secMatch) secondaryColor = secMatch[1];
    const accMatch = ds.match(/Accent color[^#]*(#[0-9a-fA-F]{6})/);
    if (accMatch) accentColor = accMatch[1];
    const headMatch = ds.match(/Heading font[^:]*:\s*([^\n]+)/);
    if (headMatch) headingFont = headMatch[1].trim();
    const bodyMatch = ds.match(/Body font[^:]*:\s*([^\n]+)/);
    if (bodyMatch) bodyFont = bodyMatch[1].trim();
    const aestheticMatch = ds.match(/Design aesthetic[^:]*:\s*([^\n]+)/);
    if (aestheticMatch) designAesthetic = aestheticMatch[1].trim();
  }

  // Extract other sections
  const dataModelMatch = prdContent.match(/## 4\.\s*Data Model[\s\S]*?(?=## 5\.|$)/);
  if (dataModelMatch) dataModel = dataModelMatch[0].trim();

  const featuresMatch = prdContent.match(/## 3\.\s*Core Features[\s\S]*?(?=## 4\.|$)/);
  if (featuresMatch) features = featuresMatch[0].trim();

  const pagesMatch = prdContent.match(/## 5\.\s*Pages & Routes[\s\S]*?(?=## 6\.|$)/);
  if (pagesMatch) pagesRoutes = pagesMatch[0].trim();

  const pricingMatch = prdContent.match(/## 7\.\s*Pricing Tiers[\s\S]*?(?=## 8\.|$)/);
  if (pricingMatch) pricingTiers = pricingMatch[0].trim();

  const integrationsMatch = prdContent.match(/## 8\.\s*Required Integrations[\s\S]*?(?=## 9\.|$)/);
  if (integrationsMatch) integrations = integrationsMatch[0].trim();

  const seoMatch = prdContent.match(/## 9\.\s*SEO Plan[\s\S]*?(?=## 10\.|$)/);
  if (seoMatch) seoKeywords = seoMatch[0].trim();

  const competitiveMatch = prdContent.match(/## 10\.\s*Competitive Weaknesses[\s\S]*?(?=## 11\.|$)/);
  if (competitiveMatch) competitiveWeaknesses = competitiveMatch[0].trim();

  const personaMatch = prdContent.match(/## 2\.\s*Target Persona[\s\S]*?(?=## 3\.|$)/);
  if (personaMatch) targetPersona = personaMatch[0].trim();

  const launchMatch = prdContent.match(/## 12\.\s*Launch Checklist[\s\S]*$/);
  if (launchMatch) launchChecklist = launchMatch[0].trim();
}

// Build a comprehensive CLAUDE.md from PRD data
let claudeMd = `# ${businessName}\n\n`;

if (prdContent) {
  claudeMd += `## Product Overview\n`;
  const overviewMatch = prdContent.match(/## 1\.\s*Product Overview[\s\S]*?(?=## 2\.|$)/);
  if (overviewMatch) {
    claudeMd += overviewMatch[0].replace(/## 1\.\s*Product Overview\s*/, '').trim() + '\n\n';
  }
} else {
  claudeMd += `## Product Overview\nA SaaS product built by The Forge.\n\n`;
}

claudeMd += `## Stack\n- Next.js 15 (App Router) + TypeScript + Tailwind CSS v4\n- Supabase (auth, database, storage)\n- Stripe (subscriptions with 14-day trial)\n- Deployed on Vercel\n\n`;

claudeMd += `## Design System\n- **Heading font**: ${headingFont} (from Google Fonts)\n- **Body font**: ${bodyFont} (from Google Fonts)\n- **Primary color**: ${primaryColor}\n- **Secondary color**: ${secondaryColor}\n- **Accent color**: ${accentColor}\n- **Aesthetic**: ${designAesthetic}\n\n`;

if (targetPersona) {
  claudeMd += targetPersona + '\n\n';
}

if (features) {
  claudeMd += features + '\n\n';
}

if (dataModel) {
  claudeMd += dataModel + '\n\n';
}

if (pagesRoutes) {
  claudeMd += pagesRoutes + '\n\n';
}

if (pricingTiers) {
  claudeMd += pricingTiers + '\n\n';
}

if (integrations) {
  claudeMd += integrations + '\n\n';
} else {
  claudeMd += `## Required Integrations\n- Supabase Auth (email + password)\n- Stripe Checkout (3 products/prices, 14-day trial)\n- Stripe webhook -> forward to n8n at \${NEXT_PUBLIC_N8N_URL}/webhook/stripe-events\n- Signup webhook -> POST to \${NEXT_PUBLIC_N8N_URL}/webhook/user-signup\n- Contact form -> POST to \${NEXT_PUBLIC_N8N_URL}/webhook/support-ticket\n- /demo route -> redirect to cal.com/shalinp\n- Plausible analytics script (data-domain from NEXT_PUBLIC_PLAUSIBLE_DOMAIN env var)\n- All n8n URLs via NEXT_PUBLIC_N8N_URL env var\n\n`;
}

if (seoKeywords) {
  claudeMd += seoKeywords + '\n\n';
}

if (competitiveWeaknesses) {
  claudeMd += competitiveWeaknesses + '\n\n';
}

claudeMd += `## Content Quality Standards (MANDATORY)\nBANNED WORDS: "delve", "leverage", "utilize", "harness", "elevate", "empower", "streamline", "robust", "seamless", "cutting-edge", "game-changer", "revolutionize", "transform", "innovative", "best-in-class", "world-class", "state-of-the-art", "paradigm", "synergy", "holistic"\nBANNED PUNCTUATION: em dashes (use regular dashes instead)\nWrite like a real person. Direct, practical, no BS. Conversational tone.\n\n`;

claudeMd += `## Development Rules\n- Always use App Router (app/ directory)\n- Use TypeScript strict mode\n- Use Tailwind CSS v4 for all styling\n- Use Supabase client from @supabase/ssr\n- All pages must be responsive (mobile-first)\n- Use Server Components by default, Client Components only when needed\n- Follow the design system defined above for ALL UI elements\n- Include sitemap.xml and robots.txt\n- Add JSON-LD structured data to landing page\n- Include OG image meta tags on all pages\n- Lighthouse targets: performance > 50, accessibility > 80, SEO > 80\n\n`;

claudeMd += `## Environment Variables (.env.example)\nNEXT_PUBLIC_SUPABASE_URL=\nNEXT_PUBLIC_SUPABASE_ANON_KEY=\nSUPABASE_SERVICE_ROLE_KEY=\nSTRIPE_SECRET_KEY=\nSTRIPE_WEBHOOK_SECRET=\nNEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY=\nNEXT_PUBLIC_N8N_URL=\nNEXT_PUBLIC_PLAUSIBLE_DOMAIN=\nNEXT_PUBLIC_SITE_URL=\n`;

if (launchChecklist) {
  claudeMd += '\n\n' + launchChecklist;
}

// Build the issue body - if we have a PRD, reference it heavily
let issueBody;
if (prdContent) {
  issueBody = `@claude Build the complete MVP for ${businessName} following the PRD and CLAUDE.md specifications exactly.\n\n## Full PRD\n\n${prdContent}\n\n## Build Instructions\n\n1. **Read CLAUDE.md first** - it contains the full design system, data model, features, routes, and integration requirements.\n\n2. **Initialize the project**:\n   - Next.js 15 with App Router, TypeScript, Tailwind CSS v4\n   - Install: @supabase/ssr, @supabase/supabase-js, stripe, @stripe/stripe-js\n\n3. **Build every page listed in the PRD** (Section 5 - Pages & Routes):\n   - Each page must match the exact routes specified\n   - Landing page needs: hero, features, pricing, testimonials, CTA, footer\n   - Dashboard must be a protected route with the full feature set\n\n4. **Implement the data model** (Section 4):\n   - Create Supabase migration SQL for all entities\n   - Include RLS policies for multi-tenant data isolation\n   - Create TypeScript types matching the schema\n\n5. **Wire up all integrations** (Section 8):\n   - Supabase Auth with email/password\n   - Stripe Checkout with 3 pricing tiers and 14-day trial\n   - Stripe webhook handler at /api/webhooks/stripe\n   - Signup webhook POST to NEXT_PUBLIC_N8N_URL/webhook/user-signup\n   - Contact form POST to NEXT_PUBLIC_N8N_URL/webhook/support-ticket\n   - /demo route redirects to cal.com/shalinp\n   - Plausible analytics script with NEXT_PUBLIC_PLAUSIBLE_DOMAIN\n\n6. **Apply the design system exactly**:\n   - Use the exact fonts from Google Fonts specified in CLAUDE.md\n   - Use the exact color palette specified\n   - Match the aesthetic description\n   - Mobile-first responsive design\n\n7. **SEO requirements**:\n   - Meta titles and descriptions on all pages\n   - OG image tags\n   - sitemap.xml and robots.txt\n   - JSON-LD structured data on landing page\n\n8. **Content standards**:\n   - NO banned words (see CLAUDE.md)\n   - NO em dashes\n   - Write like a real person\n\n9. **Create .env.example** with all required environment variables.\n\n10. **Quality gates** - the app MUST:\n    - Build without errors (npm run build)\n    - Have zero TypeScript errors\n    - Be fully mobile responsive\n    - Pass Lighthouse: performance > 50, accessibility > 80, SEO > 80\n\nCreate a PR with all changes when done.`;
} else {
  issueBody = `@claude Build the initial MVP for ${businessName}.\n\n## Instructions\n1. Read the CLAUDE.md file for design system and stack requirements.\n2. Initialize a Next.js project with TypeScript and Tailwind CSS v4.\n3. Set up the app/ directory structure with:\n   - Landing page with hero, features, pricing, CTA sections\n   - Login and signup pages (Supabase Auth)\n   - Dashboard page (protected route)\n4. Install and configure Supabase client (@supabase/ssr).\n5. Create a shared layout with navigation and footer.\n6. Apply the design system from CLAUDE.md (fonts, colors, aesthetic).\n7. Ensure all pages are mobile-responsive.\n8. Add a .env.example with all required environment variables.\n\n## Quality Gates\n- The app must build without errors (npm run build)\n- No TypeScript errors\n- All pages render correctly\n- Mobile responsive\n\nCreate a PR with all changes when done.`;
}

// Base64 encode the file contents for GitHub API
const claudeYmlB64 = Buffer.from(claudeYml).toString('base64');
const claudeMdB64 = Buffer.from(claudeMd).toString('base64');

return [{
  json: {
    businessId,
    businessName,
    repoName,
    techStack,
    prdContent,
    targetPersona,
    features,
    pricingTiers,
    claudeYmlB64,
    claudeMdB64,
    issueBody,
    issueTitle: '@claude Build initial MVP for ' + businessName,
    hasPrd: prdContent ? true : false
  }
}];

// Step 4.5 - Build Retell AI Voice Agent Config
// Reads PRD content and generates a voice agent configuration for Retell AI

const payloads = $('Prepare Payloads').first().json;
const businessId = payloads.businessId;
const businessName = payloads.businessName;
const repoName = payloads.repoName;
const prdContent = payloads.prdContent || '';
const targetPersona = payloads.targetPersona || '';
const features = payloads.features || '';
const pricingTiers = payloads.pricingTiers || '';

// Determine site URL from repoName (best guess - can be updated later)
const siteUrl = repoName ? `https://${repoName}.vercel.app` : `https://${businessName.toLowerCase().replace(/\s+/g, '')}.com`;
const bookingLink = 'https://cal.com/shalinp';

// --- Voice mapping based on target persona ---
const persona = targetPersona || businessName;
const personaLower = persona.toLowerCase();
let voiceId, voiceName;

if (personaLower.includes('auto') || personaLower.includes('mechanic') || personaLower.includes('construction') || personaLower.includes('plumbing') || personaLower.includes('hvac') || personaLower.includes('electrician')) {
  voiceId = 'professional_male_mature';
  voiceName = 'Professional Male (35-50)';
} else if (personaLower.includes('salon') || personaLower.includes('spa') || personaLower.includes('beauty') || personaLower.includes('yoga') || personaLower.includes('fitness') || personaLower.includes('wellness')) {
  voiceId = 'friendly_female_young';
  voiceName = 'Friendly Female (25-35)';
} else if (personaLower.includes('law') || personaLower.includes('legal') || personaLower.includes('accounting') || personaLower.includes('financial') || personaLower.includes('consulting')) {
  voiceId = 'authoritative_male_senior';
  voiceName = 'Authoritative Male (45-60)';
} else if (personaLower.includes('tutor') || personaLower.includes('coach') || personaLower.includes('teacher') || personaLower.includes('education')) {
  voiceId = 'warm_female_mid';
  voiceName = 'Warm Female (28-40)';
} else if (personaLower.includes('photography') || personaLower.includes('creative') || personaLower.includes('design') || personaLower.includes('marketing')) {
  voiceId = 'energetic_female_young';
  voiceName = 'Energetic Female (25-35)';
} else {
  voiceId = 'professional_male_mid';
  voiceName = 'Professional Male (30-40)';
}

// --- Extract product info from PRD for the sales script ---
let oneLineDescription = `software built for ${personaLower.includes('auto') ? 'auto repair shops' : personaLower.includes('salon') ? 'salons' : 'small businesses'}`;
let topFeatures = '';
let pricingLine = '$49/month';
let trialDays = '14';
let productType = 'management software';
let personaType = 'business owners';

if (prdContent) {
  // Try to extract one-line description from Product Overview
  const overviewMatch = prdContent.match(/## 1\.\s*Product Overview[\s\S]*?(?=## 2\.|$)/);
  if (overviewMatch) {
    const overviewLines = overviewMatch[0].replace(/## 1\.\s*Product Overview\s*/, '').trim().split('\n').filter(l => l.trim());
    if (overviewLines.length > 0) {
      oneLineDescription = overviewLines[0].replace(/^[-*]\s*/, '').trim();
      if (oneLineDescription.length > 120) oneLineDescription = oneLineDescription.substring(0, 117) + '...';
    }
  }

  // Extract top features (first 4 bullet points from Core Features)
  if (features) {
    const featureLines = features.split('\n').filter(l => l.trim().match(/^[-*]/)).slice(0, 4);
    topFeatures = featureLines.map(l => l.replace(/^[-*]\s*/, '').trim()).join('\n- ');
    if (topFeatures) topFeatures = '- ' + topFeatures;
  }

  // Extract pricing
  if (pricingTiers) {
    const priceMatch = pricingTiers.match(/\$\d+\/month|\$\d+\/mo/);
    if (priceMatch) pricingLine = priceMatch[0];
    const trialMatch = pricingTiers.match(/(\d+)[- ]day\s*(free\s*)?trial/i);
    if (trialMatch) trialDays = trialMatch[1];
  }

  // Determine persona type from Target Persona section
  if (targetPersona) {
    const personaLines = targetPersona.split('\n').filter(l => l.trim()).slice(0, 3);
    const firstLine = personaLines.find(l => !l.startsWith('#'));
    if (firstLine) {
      personaType = firstLine.replace(/^[-*]\s*/, '').trim();
      if (personaType.length > 60) personaType = personaType.substring(0, 57) + '...';
    }
  }
} else {
  // Fallback: generic features
  topFeatures = '- Easy scheduling and appointment management\n- Invoicing and payments\n- Customer management\n- Mobile-friendly dashboard';
}

// --- Build the sales script ---
let scriptContent = `You are calling on behalf of ${businessName}, ${oneLineDescription}.
You're calling {prospect_name} at {prospect_business}.

Your goal: Book a 15-minute demo at {booking_link}

Key selling points:
${topFeatures || '- All-in-one management platform\n- Save hours on paperwork every week\n- Easy setup, no technical knowledge needed\n- Mobile-friendly'}

Pricing: ${pricingLine}. ${trialDays}-day free trial, no credit card needed.

If interested: 'Great, I can get you set up with a quick 15-minute walkthrough. Would [suggest two specific times this week] work for you?'

If voicemail: 'Hey {prospect_name}, quick call about ${businessName} - we built ${productType} specifically for ${personaType}. Check out ${siteUrl} or I'll try you again in a couple days.'

If not interested: 'No problem at all. If things change, we're at ${siteUrl}. Have a great day.'

Be natural, conversational, not salesy. Get to the point fast - ${personaType} are busy.`;

// Extract boosted keywords from business name and key terms
const boostedKeywords = [businessName];
if (features) {
  // Pull key nouns from feature names
  const featureWords = features.match(/\b(scheduling|invoicing|inspection|dashboard|booking|payment|CRM|inventory|reporting|analytics|automation)\b/gi);
  if (featureWords) {
    featureWords.slice(0, 5).forEach(w => {
      if (!boostedKeywords.includes(w)) boostedKeywords.push(w);
    });
  }
}

return [{
  json: {
    businessId,
    businessName,
    repoName,
    siteUrl,
    bookingLink,
    voiceId,
    voiceName,
    scriptContent,
    boostedKeywords,
    agentName: businessId + '_sales_agent'
  }
}];

// Parse Retell API response and prepare data for Knowledge Graph update
const retellResponse = $input.first().json;
const configData = $('Step 4.5a - Build Retell Agent Config').first().json;

let retellAgentId = '';
let retellCreated = false;
let retellError = '';

// Check if Retell API returned an agent_id
if (retellResponse && retellResponse.agent_id) {
  retellAgentId = retellResponse.agent_id;
  retellCreated = true;
} else if (retellResponse && retellResponse.error) {
  retellError = typeof retellResponse.error === 'string' ? retellResponse.error : JSON.stringify(retellResponse.error);
} else {
  retellError = 'Retell API did not return an agent_id. Response: ' + JSON.stringify(retellResponse).substring(0, 200);
}

return [{
  json: {
    retellAgentId,
    retellCreated,
    retellError,
    voiceName: configData.voiceName,
    siteUrl: configData.siteUrl,
    repoName: configData.repoName,
    bookingLink: configData.bookingLink
  }
}];

const phoneResult = $input.first().json;
const prevData = $('Step 4.5c - Parse Retell Response').first().json;

const phoneNumber = phoneResult.phone_number || phoneResult.number || '';
const phoneId = phoneResult.phone_number_id || phoneResult.id || '';

return [{
  json: {
    ...prevData,
    retellPhoneNumber: phoneNumber,
    retellPhoneId: phoneId,
    phoneProvisionError: phoneNumber ? null : 'Failed to provision phone number'
  }
}];
